492 static bool isSelect01(const APInt &C1I, const APInt &C2I) {
493   if (!C1I.isZero() && !C2I.isZero()) // One side must be zero.
494     return false;
495   return C1I.isOne() || C1I.isAllOnes() || C2I.isOne() || C2I.isAllOnes();
496 }
